+// cloneOnComplete creates a deep copy of an OnCompleteSpec (gt-8tmz.8).
+func cloneOnComplete(oc *OnCompleteSpec) *OnCompleteSpec {
+	if oc == nil {
+		return nil
+	}
+	clone := *oc
+	if len(oc.Vars) > 0 {
+		clone.Vars = make(map[string]string, len(oc.Vars))
+		for k, v := range oc.Vars {
+			clone.Vars[k] = v
+		}
+	}
+	return &clone
+}
